# Category: ssrf

local http = require "resty.http"

ngx.req.read_body()

local target_url = ngx.var.arg_url

if not target_url or target_url == "" then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say('{"error": "Missing required parameter: url"}')
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

local parsed = require("resty.http").new()

-- Validate the URL scheme
if not (target_url:match("^https?://")) then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say('{"error": "Invalid URL scheme. Only http and https are supported."}')
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

-- Block private/internal network ranges to prevent SSRF
local function is_blocked_host(url)
    local host = url:match("^https?://([^/:]+)")
    if not host then
        return true
    end

    -- Block localhost and common internal hostnames
    local blocked_hosts = {
        "localhost",
        "127%.%d+%.%d+%.%d+",
        "10%.%d+%.%d+%.%d+",
        "172%.1[6-9]%.%d+%.%d+",
        "172%.2%d%.%d+%.%d+",
        "172%.3[0-1]%.%d+%.%d+",
        "192%.168%.%d+%.%d+",
        "0%.0%.0%.0",
        "169%.254%.%d+%.%d+",
        "%[::1%]",
        "%[fc",
        "%[fd",
        "%[fe80",
    }

    local lower_host = host:lower()
    for _, pattern in ipairs(blocked_hosts) do
        if lower_host:match(pattern) then
            return true
        end
    end

    return false
end

if is_blocked_host(target_url) then
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.say('{"error": "Access to internal/private networks is not allowed."}')
    return ngx.exit(ngx.HTTP_FORBIDDEN)
end

-- Capture the incoming request method and headers to forward
local request_method = ngx.req.get_method()
local request_headers = ngx.req.get_headers()
local request_body = ngx.req.get_body_data()

-- Remove hop-by-hop headers that should not be forwarded
local hop_by_hop_headers = {
    "connection",
    "keep-alive",
    "proxy-authenticate",
    "proxy-authorization",
    "te",
    "trailers",
    "transfer-encoding",
    "upgrade",
    "host",
}

local forward_headers = {}
for k, v in pairs(request_headers) do
    local dominated = false
    for _, hbh in ipairs(hop_by_hop_headers) do
        if k:lower() == hbh then
            dominated = true
            break
        end
    end
    if not dominated then
        forward_headers[k] = v
    end
end

-- Add forwarding headers
forward_headers["X-Forwarded-For"] = ngx.var.remote_addr
forward_headers["X-Forwarded-Proto"] = ngx.var.scheme
forward_headers["X-Webhook-Proxy"] = "openresty-webhook-forwarder"

local httpc = http.new()

-- Set reasonable timeouts (connect, send, read in ms)
httpc:set_timeouts(5000, 10000, 15000)

local res, err = httpc:request_uri(target_url, {
    method = request_method,
    headers = forward_headers,
    body = request_body,
    ssl_verify = true,
    -- Limit max redirects
    max_redirects = 3,
})

if not res then
    ngx.status = ngx.HTTP_BAD_GATEWAY
    ngx.header["Content-Type"] = "application/json"
    ngx.say('{"error": "Failed to proxy request", "detail": "' .. (err or "unknown error") .. '"}')
    ngx.log(ngx.ERR, "webhook proxy failed for url: ", target_url, " error: ", err)
    return ngx.exit(ngx.HTTP_BAD_GATEWAY)
end

-- Forward the response status
ngx.status = res.status

-- Forward response headers, excluding hop-by-hop headers
if res.headers then
    for k, v in pairs(res.headers) do
        local dominated = false
        for _, hbh in ipairs(hop_by_hop_headers) do
            if k:lower() == hbh then
                dominated = true
                break
            end
        end
        if not dominated then
            ngx.header[k] = v
        end
    end
end

-- Add custom response headers for debugging
ngx.header["X-Proxy-Status"] = "forwarded"
ngx.header["X-Upstream-Status"] = res.status
ngx.header["X-Target-URL"] = target_url

-- Send the response body
if res.body then
    ngx.say(res.body)
else
    ngx.say("")
end

ngx.log(ngx.INFO, "webhook proxy success - url: ", target_url,
    " method: ", request_method,
    " upstream_status: ", res.status,
    " client: ", ngx.var.remote_addr)

return ngx.exit(ngx.status)